//! probe-rknot — Phase 3 smoke loader for Resonance Knot files
//!
//! Usage:
//!   probe-rknot --rknot <path.rknot> [--probe "What is the capital of France?"]
//!
//! Phase 3 contract (`RKNOT_PHASE3_CONTRACTS.md` Module 3):
//!
//!   1. Load a `.rknot` from disk via [`reader::read_rknot_from_file`].
//!   2. Decode every layer's Q / K / V blocks via
//!      [`decoder::decode_block`] and the FFN block via
//!      [`decoder::decode_ffn_block`]. Time each decode and capture the
//!      maximum absolute value (sanity check: any NaN in the decoded
//!      tensor flips a per-block warning bit).
//!   3. Print per-layer rows (decode time + max abs value).
//!   4. Print a summary (total decoded bytes, total decode time, mean /
//!      max / non-zero fraction across all decoded blocks).
//!   5. Print a Phase 4 placeholder line — Phase 4 will wire real
//!      inference; Phase 3 just proves the file can be loaded and decoded
//!      end-to-end.
//!
//! No external dependencies — everything uses the existing
//! `distributed_inference::rknot` API.

use std::path::PathBuf;
use std::process::ExitCode;
use std::time::{Duration, Instant};

use distributed_inference::rknot::decoder::*;
use distributed_inference::rknot::format::*;
use distributed_inference::rknot::reader::*;

// ──────────────────────────────────────────────────────────────────────
// CLI
// ──────────────────────────────────────────────────────────────────────

#[derive(Debug, Default)]
struct Args {
    rknot: Option<PathBuf>,
    probe: Option<String>,
}

fn print_usage() {
    eprintln!(
        "probe-rknot — Phase 3 smoke loader for Resonance Knot files

USAGE:
  probe-rknot --rknot <path.rknot> [--probe \"What is the capital of France?\"]

FLAGS:
  --rknot <path>   Path to the .rknot under test (required)
  --probe <text>   Stub probe text — printed back as a Phase 4 placeholder
  -h, --help       Print this message"
    );
}

fn parse_args() -> Result<Args, String> {
    let mut args = Args::default();
    let mut iter = std::env::args().skip(1);
    while let Some(flag) = iter.next() {
        match flag.as_str() {
            "--rknot" => {
                let v = iter
                    .next()
                    .ok_or_else(|| "--rknot requires a path".to_string())?;
                args.rknot = Some(PathBuf::from(v));
            }
            "--probe" => {
                let v = iter
                    .next()
                    .ok_or_else(|| "--probe requires a value".to_string())?;
                args.probe = Some(v);
            }
            "-h" | "--help" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown argument: {other}")),
        }
    }
    if args.rknot.is_none() {
        return Err("--rknot <path> is required".to_string());
    }
    Ok(args)
}

// ──────────────────────────────────────────────────────────────────────
// Per-block measurement
// ──────────────────────────────────────────────────────────────────────

/// Measurement captured for a single decoded block. Aggregated into the
/// run summary; printed verbatim for per-layer rows.
#[derive(Debug, Clone, Copy)]
struct BlockSmoke {
    /// Decoded byte count = `rows × cols × 4` (decoded values are f32).
    decoded_bytes: u64,
    /// Wall-clock decode time. Captures both unpacking and the standing-
    /// projection write-back cost in `decode_block` / `decode_ffn_block`.
    decode_time: Duration,
    /// `max |x|` across the decoded tensor. Returns `f32::NAN` if any
    /// decoded value is itself NaN (NaN propagates through max — we use
    /// an explicit `is_nan` check below so that even one NaN element
    /// surfaces in the per-layer report).
    max_abs: f32,
    /// Mean absolute value across the decoded tensor (NaN values count
    /// as zero contribution to keep the running mean finite even when a
    /// block has NaNs — the `nan_count` field flags the failure).
    mean_abs: f32,
    /// Fraction of decoded values that are non-zero. Standing-wave
    /// blocks are sparse: roughly `(k/d)^2` for Q/K/V and `k/d` for FFN.
    /// A near-zero fraction means decode worked but the manifest is
    /// degenerate; a near-one fraction with a real `.rknot` is suspicious.
    non_zero_fraction: f32,
    /// Number of NaN values observed. Non-zero ⇒ printed warning.
    nan_count: u64,
}

/// Inspect a decoded `DenseTensor` and produce a [`BlockSmoke`] record.
/// Tracks NaNs explicitly so a single bad value flips the per-block warn
/// bit instead of silently passing through `f32::max`.
fn measure_decoded(decoded: &DenseTensor, decode_time: Duration) -> BlockSmoke {
    let mut max_abs = 0.0_f32;
    let mut sum_abs = 0.0_f64;
    let mut non_zero = 0_u64;
    let mut nan_count = 0_u64;
    for &v in &decoded.data {
        if v.is_nan() {
            nan_count += 1;
            continue;
        }
        let a = v.abs();
        if a > max_abs {
            max_abs = a;
        }
        sum_abs += a as f64;
        if v != 0.0 {
            non_zero += 1;
        }
    }
    let elem_count = decoded.data.len() as u64;
    let mean_abs = if elem_count == 0 {
        0.0
    } else {
        (sum_abs / elem_count as f64) as f32
    };
    let non_zero_fraction = if elem_count == 0 {
        0.0
    } else {
        non_zero as f32 / elem_count as f32
    };
    // If any NaNs surfaced, surface that fact in `max_abs` too so the
    // per-layer print line reads `NaN` rather than a misleading finite
    // number.
    let max_abs = if nan_count > 0 { f32::NAN } else { max_abs };
    BlockSmoke {
        decoded_bytes: elem_count * 4,
        decode_time,
        max_abs,
        mean_abs,
        non_zero_fraction,
        nan_count,
    }
}

/// Decode one block and time the call. The closure pattern lets us reuse
/// the same timing wrapper for both `decode_block` (Q/K/V) and
/// `decode_ffn_block` (FFN, which needs the FFN intermediate dim).
fn decode_and_measure<F>(decode_fn: F) -> BlockSmoke
where
    F: FnOnce() -> DenseTensor,
{
    let t0 = Instant::now();
    let decoded = decode_fn();
    let elapsed = t0.elapsed();
    measure_decoded(&decoded, elapsed)
}

// ──────────────────────────────────────────────────────────────────────
// Run summary aggregation
// ──────────────────────────────────────────────────────────────────────

/// Whole-run aggregate of per-block measurements. Used both by `main`
/// for the bottom-of-output summary and by the unit tests for shape
/// assertions (`decode_summary_dimensions_match_layer_count`).
#[derive(Debug, Default, Clone, Copy)]
struct DecodeSummary {
    layers_decoded: u32,
    blocks_decoded: u32,
    total_decoded_bytes: u64,
    total_decode_time: Duration,
    /// Sum of `mean_abs` across blocks; divided by `blocks_decoded` for
    /// reporting. Stored as f64 to keep the running sum honest across
    /// 80-layer Llama-70B (320 blocks) without f32 catastrophic loss.
    sum_mean_abs: f64,
    /// Max of `max_abs` across blocks; non-zero NaN total flips the
    /// summary into a NaN-flagged state.
    max_max_abs: f32,
    sum_non_zero_fraction: f64,
    nan_blocks: u32,
}

impl DecodeSummary {
    fn add_block(&mut self, m: &BlockSmoke) {
        self.blocks_decoded += 1;
        self.total_decoded_bytes += m.decoded_bytes;
        self.total_decode_time += m.decode_time;
        self.sum_mean_abs += m.mean_abs as f64;
        if m.nan_count > 0 {
            self.nan_blocks += 1;
        } else if m.max_abs > self.max_max_abs {
            self.max_max_abs = m.max_abs;
        }
        self.sum_non_zero_fraction += m.non_zero_fraction as f64;
    }

    fn mean_abs(&self) -> f32 {
        if self.blocks_decoded == 0 {
            0.0
        } else {
            (self.sum_mean_abs / self.blocks_decoded as f64) as f32
        }
    }

    fn non_zero_fraction(&self) -> f32 {
        if self.blocks_decoded == 0 {
            0.0
        } else {
            (self.sum_non_zero_fraction / self.blocks_decoded as f64) as f32
        }
    }
}

// ──────────────────────────────────────────────────────────────────────
// Per-layer print
// ──────────────────────────────────────────────────────────────────────

fn print_block_row(layer_idx: u32, label: &str, m: &BlockSmoke) {
    let warn = if m.nan_count > 0 { "WARN " } else { "     " };
    let max_str = if m.nan_count > 0 {
        format!("NaN×{}", m.nan_count)
    } else {
        format!("{:.4e}", m.max_abs)
    };
    println!(
        "{warn}L{:>3} {:>3}: decode={:>9.3?} max_abs={:>14} mean_abs={:.4e} nz={:.4}",
        layer_idx, label, m.decode_time, max_str, m.mean_abs, m.non_zero_fraction,
    );
}

/// Decode a full layer (Q, K, V, FFN), feeding each block's measurement
/// into the running summary and printing a per-block row. The FFN
/// intermediate dim is read from `layer.ffn_block.cols` — the dense
/// reader sets that to the actual GGUF intermediate size at encode time.
fn decode_layer(layer: &ResonanceKnotLayer, summary: &mut DecodeSummary) {
    let manifest = &layer.manifest;
    let intermediate_h = layer.ffn_block.cols;

    let q_smoke = decode_and_measure(|| decode_block(&layer.q_block, manifest));
    print_block_row(layer.layer_idx, "Q", &q_smoke);
    summary.add_block(&q_smoke);

    let k_smoke = decode_and_measure(|| decode_block(&layer.k_block, manifest));
    print_block_row(layer.layer_idx, "K", &k_smoke);
    summary.add_block(&k_smoke);

    let v_smoke = decode_and_measure(|| decode_block(&layer.v_block, manifest));
    print_block_row(layer.layer_idx, "V", &v_smoke);
    summary.add_block(&v_smoke);

    let ffn_smoke =
        decode_and_measure(|| decode_ffn_block(&layer.ffn_block, manifest, intermediate_h));
    print_block_row(layer.layer_idx, "FFN", &ffn_smoke);
    summary.add_block(&ffn_smoke);
}

// ──────────────────────────────────────────────────────────────────────
// main
// ──────────────────────────────────────────────────────────────────────

fn main() -> ExitCode {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("probe-rknot: {e}");
            print_usage();
            return ExitCode::from(2);
        }
    };
    let rknot_path = args.rknot.expect("validated above");

    eprintln!(
        "probe-rknot: rknot={} probe={:?}",
        rknot_path.display(),
        args.probe.as_deref(),
    );

    let load_t0 = Instant::now();
    let rknot = match read_rknot_from_file(&rknot_path) {
        Ok(r) => r,
        Err(e) => {
            eprintln!("probe-rknot: failed to read .rknot: {e}");
            return ExitCode::from(1);
        }
    };
    let load_elapsed = load_t0.elapsed();

    eprintln!(
        "probe-rknot: loaded {} layers (arch={}, hidden_dim={}, encoder_version={}) in {:?}",
        rknot.layers.len(),
        rknot.arch_meta.arch,
        rknot.arch_meta.hidden_dim,
        rknot.encoder_version,
        load_elapsed,
    );

    let mut summary = DecodeSummary::default();
    for layer in &rknot.layers {
        decode_layer(layer, &mut summary);
        summary.layers_decoded += 1;
    }

    eprintln!();
    eprintln!("── probe-rknot summary ──");
    eprintln!("layers decoded:           {:>10}", summary.layers_decoded);
    eprintln!("blocks decoded:           {:>10}", summary.blocks_decoded);
    eprintln!(
        "total decoded bytes:      {:>10}",
        summary.total_decoded_bytes
    );
    eprintln!(
        "total decode time:        {:>10.3?}",
        summary.total_decode_time
    );
    eprintln!("mean abs (across blocks): {:>10.4e}", summary.mean_abs());
    if summary.nan_blocks > 0 {
        eprintln!(
            "max abs (across blocks):           NaN ({} block(s) contained NaNs)",
            summary.nan_blocks
        );
    } else {
        eprintln!("max abs (across blocks):  {:>10.4e}", summary.max_max_abs);
    }
    eprintln!(
        "non-zero fraction (mean): {:>10.4}",
        summary.non_zero_fraction()
    );

    // Phase 4 placeholder — real inference (the "Paris" probe) lands in
    // Phase 4. Phase 3 only proves load + decode end-to-end.
    eprintln!();
    let probe_text = args
        .probe
        .as_deref()
        .unwrap_or("(no --probe text provided)");
    eprintln!(
        "[phase4-placeholder] would generate text from probe: {:?}",
        probe_text
    );

    if summary.nan_blocks > 0 {
        ExitCode::from(1)
    } else {
        ExitCode::SUCCESS
    }
}

// ──────────────────────────────────────────────────────────────────────
// Tests — unit-only per Module 3 contract.
//
//   * `decode_summary_dimensions_match_layer_count` — feed a synthetic
//     `Rknot` with N layers through the per-layer aggregator, assert the
//     summary reports `N` layers and `4N` blocks decoded.
//   * `decode_detects_nan` — synthesize a `QuantBlock` whose decoded
//     payload is forced to contain a NaN, run it through
//     `measure_decoded`, assert `nan_count > 0`.
// ──────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    /// Build a small synthetic `ResonanceKnotLayer` whose blocks decode
    /// to dense f32 tensors with no NaNs. The block payloads are all
    /// zeros, which is fine for the dimension-counting test — the
    /// decoder will produce all-zero standing entries, still a valid
    /// `DenseTensor` of the right shape.
    fn synthetic_layer(layer_idx: u32) -> ResonanceKnotLayer {
        let manifest = SpectralManifest {
            d: 8,
            k: 4,
            standing_indices: vec![0, 2, 4, 6],
            amplitudes: vec![1.0; 4],
            phase_alignment: vec![1.0; 4],
        };
        // 4 × 4 × 4 bits = 64 bits = 8 bytes.
        let qkv_payload = vec![0u8; 8];
        // 4 × 16 × 4 bits = 256 bits = 32 bytes.
        let ffn_payload = vec![0u8; 32];
        ResonanceKnotLayer {
            layer_idx,
            manifest: manifest.clone(),
            q_block: QuantBlock {
                rows: 4,
                cols: 4,
                bits_per_entry: 4,
                payload: qkv_payload.clone(),
            },
            k_block: QuantBlock {
                rows: 4,
                cols: 4,
                bits_per_entry: 4,
                payload: qkv_payload.clone(),
            },
            v_block: QuantBlock {
                rows: 4,
                cols: 4,
                bits_per_entry: 4,
                payload: qkv_payload,
            },
            ffn_block: QuantBlock {
                rows: 4,
                cols: 16,
                bits_per_entry: 4,
                payload: ffn_payload,
            },
        }
    }

    /// Per Module 3: summary's `layers_decoded` and `blocks_decoded`
    /// must agree with the input layer count (one layer ⇒ four blocks).
    #[test]
    fn decode_summary_dimensions_match_layer_count() {
        let mut summary = DecodeSummary::default();
        let layers: Vec<ResonanceKnotLayer> = (0..3).map(synthetic_layer).collect();
        for layer in &layers {
            decode_layer(layer, &mut summary);
            summary.layers_decoded += 1;
        }
        assert_eq!(summary.layers_decoded, 3);
        assert_eq!(
            summary.blocks_decoded, 12,
            "3 layers × 4 blocks/layer = 12 decoded blocks"
        );
        assert_eq!(summary.nan_blocks, 0, "synthetic zeros don't produce NaN");
    }

    /// Per Module 3: a decoded tensor containing a NaN value must
    /// surface in `BlockSmoke::nan_count` so the per-block warning row
    /// (and the summary's `nan_blocks` counter) flag the failure.
    #[test]
    fn decode_detects_nan() {
        // Bypass `decode_block` and inject NaN directly into a synthetic
        // decoded tensor — this is the same surface
        // `measure_decoded` would observe if a real decoder ever produced
        // a NaN (e.g. Phase 4 fp48 unpacker bug).
        let mut data = vec![0.5_f32; 16];
        data[7] = f32::NAN;
        let decoded = DenseTensor {
            rows: 4,
            cols: 4,
            data,
        };
        let smoke = measure_decoded(&decoded, Duration::from_micros(1));
        assert_eq!(smoke.nan_count, 1, "single NaN must be counted");
        assert!(smoke.max_abs.is_nan(), "max_abs flips to NaN under any NaN");
        // Mean is `sum(non-NaN |x|) / total_elem_count` (NaN contributes
        // 0 to the sum but still counts toward the divisor — see
        // BlockSmoke::mean_abs docs). 15 × 0.5 / 16 = 0.46875.
        let expected_mean = 15.0_f32 * 0.5 / 16.0;
        assert!(
            (smoke.mean_abs - expected_mean).abs() < 1e-6,
            "mean_abs = {} vs expected {}",
            smoke.mean_abs,
            expected_mean
        );

        // Multi-NaN: two NaNs in a 4-element block triggers nan_count = 2.
        let data2 = vec![f32::NAN, 0.0, f32::NAN, 1.0];
        let decoded2 = DenseTensor {
            rows: 2,
            cols: 2,
            data: data2,
        };
        let smoke2 = measure_decoded(&decoded2, Duration::from_micros(1));
        assert_eq!(smoke2.nan_count, 2);

        // Aggregating a NaN-bearing block into the summary flips
        // `nan_blocks`.
        let mut summary = DecodeSummary::default();
        summary.add_block(&smoke);
        summary.add_block(&smoke2);
        assert_eq!(summary.nan_blocks, 2);
    }
}
